{"path":"src/db.rs","content":"use crate::api::*;
use crate::distance::l2_distance;
use std::collections::HashMap;
use std::sync::RwLock;

pub struct VectorDB {
    // Store vectors contiguously for cache efficiency
    vectors: RwLock<Vec<Vec<f32>>>,
    // Map from ID to index in vectors array
    id_to_idx: RwLock<HashMap<u64, usize>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
            id_to_idx: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        let mut id_to_idx = self.id_to_idx.write().unwrap();

        let idx = vectors.len();
        vectors.push(vector);
        id_to_idx.insert(id, idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vecs = self.vectors.write().unwrap();
        let mut id_to_idx = self.id_to_idx.write().unwrap();

        let count = vectors.len();
        for (id, vector) in vectors {
            let idx = vecs.len();
            vecs.push(vector);
            id_to_idx.insert(id, idx);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();
        let id_to_idx = self.id_to_idx.read().unwrap();

        // Create reverse mapping: index -> id
        let mut idx_to_id: HashMap<usize, u64> = HashMap::new();
        for (&id, &idx) in id_to_idx.iter() {
            idx_to_id.insert(idx, id);
        }

        // Compute all distances
        let mut results: Vec<SearchResult> = vectors
            .iter()
            .enumerate()
            .map(|(idx, vec)| {
                let distance = l2_distance(query, vec);
                SearchResult {
                    id: idx_to_id[&idx],
                    distance,
                }
            })
            .collect();

        // Sort by distance and return top_k
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results.truncate(top_k as usize);
        results
    }
}
"}

{"path":"src/distance.rs","content":"#[cfg(target_arch = "x86_64")]
use std::arch::x86_64::*;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
pub unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();

    // Process 16 floats at a time (128 / 16 = 8 iterations)
    for i in (0..a.len()).step_by(16) {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        // Use fused multiply-add for better precision and performance
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum of all 16 lanes
    let result = _mm512_reduce_add_ps(sum);
    (result as f64).sqrt()
}

#[cfg(target_arch = "x86_64")]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    unsafe {
        // Check if AVX-512 is supported at runtime
        if is_x86_feature_detected!("avx512f") {
            l2_distance_avx512(a, b)
        } else {
            l2_distance_fallback(a, b)
        }
    }
}

#[cfg(not(target_arch = "x86_64"))]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_fallback(a, b)
}

fn l2_distance_fallback(a: &[f32], b: &[f32]) -> f64 {
    let mut sum: f32 = 0.0;
    for i in 0..a.len() {
        let diff = a[i] - b[i];
        sum += diff * diff;
    }
    sum.sqrt() as f64
}
"}

