    data: RwLock<Vec<f32>>,
    // Store IDs in the same order as vectors
    ids: RwLock<Vec<u64>>,
    // Dimensionality (fixed at 128)
    dim: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            dim: 128,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        let mut ids = self.ids.write().unwrap();

        data.extend(vector);
        ids.push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let mut ids = self.ids.write().unwrap();

        let count = vectors.len();
        for (id, vector) in vectors {
            data.extend(vector);
            ids.push(id);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let ids = self.ids.read().unwrap();

        let n = ids.len();
        let dim = self.dim;

        // Compute all distances in parallel using rayon
        let mut results: Vec<SearchResult> = (0..n)
            .into_par_iter()
            .map(|i| {
                let start = i * dim;
                let vec_slice = &data[start..start + dim];
                let distance = l2_distance(query, vec_slice);
                SearchResult {
                    id: ids[i],
                    distance,
                }
            })
            .collect();

        // Sort by distance and return top_k
        // Use select_nth_unstable for better performance when we only need top_k
        let k = top_k as usize;
        if results.len() > k {
            results.select_nth_unstable_by(k, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap()
            });
            results.truncate(k);
        } else {
            results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        }

        results
    }
}
