use crate::distance::l2_distance;
use rayon::prelude::*;
use std::sync::{Arc, RwLock};
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Immutable data structure for efficient search
struct VectorData {
    data: Vec<f32>,  // Flat array of vectors
    ids: Vec<u64>,   // IDs corresponding to each vector
    dim: usize,      // Dimensionality (128)
}

pub struct VectorDB {
    inner: RwLock<Arc<VectorData>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Arc::new(VectorData {
                data: Vec::new(),
                ids: Vec::new(),
                dim: 128,
            })),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.inner.write().unwrap();
        let old = Arc::clone(&guard);

        // Check if we have exclusive access (no other Arc references)
        if Arc::strong_count(&old) == 1 {
            let vec_data = Arc::get_mut(&mut guard).unwrap();
            vec_data.data.extend(vector);
            vec_data.ids.push(id);
        } else {
            let mut data = old.data.clone();
            let mut ids = old.ids.clone();

            data.extend(vector);
            ids.push(id);

            *guard = Arc::new(VectorData {
                data,
                ids,
                dim: old.dim,
            });
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut guard = self.inner.write().unwrap();
        let old = Arc::clone(&guard);

        let count = vectors.len();

        if Arc::strong_count(&old) == 1 {
            let vec_data = Arc::get_mut(&mut guard).unwrap();
            vec_data.data.reserve(count * 128);
            vec_data.ids.reserve(count);
            for (id, vector) in vectors {
                vec_data.data.extend(vector);
                vec_data.ids.push(id);
            }
        } else {
            let mut data = Vec::with_capacity(old.data.len() + count * 128);
            let mut ids = Vec::with_capacity(old.ids.len() + count);

            data.extend_from_slice(&old.data);
            ids.extend_from_slice(&old.ids);

            for (id, vector) in vectors {
                data.extend(vector);
                ids.push(id);
            }

            *guard = Arc::new(VectorData {
                data,
                ids,
                dim: old.dim,
            });
        }

        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vec_data = Arc::clone(&self.inner.read().unwrap());

        let n = vec_data.ids.len();
        let dim = vec_data.dim;
        let k = top_k as usize;

        // Process in chunks to reduce rayon overhead
        let chunk_size = 10000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        // Each chunk maintains its own top-k using a max heap
        let chunk_results: Vec<Vec<(f64, u64)>> = (0..n_chunks)
            .into_par_iter()
            .map(|chunk_idx| {
                let start_idx = chunk_idx * chunk_size;
                let end_idx = std::cmp::min(start_idx + chunk_size, n);

                // Max heap to keep track of k smallest distances
                let mut heap: BinaryHeap<(OrderedFloat, u64)> = BinaryHeap::with_capacity(k + 1);

                for i in start_idx..end_idx {
                    let vec_start = i * dim;
                    let vec_slice = &vec_data.data[vec_start..vec_start + dim];
                    let distance = l2_distance(query, vec_slice);

                    heap.push((OrderedFloat(distance), vec_data.ids[i]));
                    if heap.len() > k {
                        heap.pop();
                    }
                }

                heap.into_iter().map(|(d, id)| (d.0, id)).collect()
            })
            .collect();

        // Merge results from all chunks
        let mut final_heap: BinaryHeap<(OrderedFloat, u64)> = BinaryHeap::with_capacity(k + 1);
        for chunk in chunk_results {
            for (distance, id) in chunk {
                final_heap.push((OrderedFloat(distance), id));
                if final_heap.len() > k {
                    final_heap.pop();
                }
            }
        }

        // Convert heap to sorted vector
        let mut results: Vec<SearchResult> = final_heap
            .into_iter()
            .map(|(d, id)| SearchResult { id, distance: d.0 })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}

// Wrapper for f64 to use in BinaryHeap (max heap)
struct OrderedFloat(f64);

impl PartialEq for OrderedFloat {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Eq for OrderedFloat {}

impl PartialOrd for OrderedFloat {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> Ordering {
        // Reverse ordering for min-heap behavior in max-heap
        other.0.partial_cmp(&self.0).unwrap()
    }
}
